-- Launch 28 follow-up: promote curated pantry bundles after the full ingredient seed.
-- Also records source-name synonyms for reviewed rename decisions that users may search or import.

with rename_synonyms(id, standard_name, synonym) as (
  values
    ('670e8400-e29b-41d4-a716-446655440601'::uuid, '라임즙', '라임 주스'),
    ('670e8400-e29b-41d4-a716-446655440602'::uuid, '라임즙', '라임주스'),
    ('670e8400-e29b-41d4-a716-446655440603'::uuid, '레몬즙', '레몬 착즙'),
    ('670e8400-e29b-41d4-a716-446655440604'::uuid, '레몬즙', '레몬착즙'),
    ('670e8400-e29b-41d4-a716-446655440605'::uuid, '쌀밥', '멥쌀밥')
)
insert into public.ingredient_synonyms (id, ingredient_id, synonym)
select rename_synonyms.id, ingredients.id, lower(trim(rename_synonyms.synonym))
from rename_synonyms
join public.ingredients
  on ingredients.standard_name = rename_synonyms.standard_name
where lower(trim(rename_synonyms.synonym)) <> lower(trim(rename_synonyms.standard_name))
on conflict do nothing;

